algorithm:
Greedy insertion with rollback-based incremental cost evaluation across all non-empty and empty assigns, selecting the minimal positive-cost increase per ship.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	// Helper to check if assign is usable (has stations or is empty slot within current length)
	isUsable := func(idx int) bool {
		if idx < 0 || idx >= MAXASSIGNS {
			return false
		}
		// Existing non‑empty assign or an empty slot at the end
		return idx < dispatch.AssignsLen || (idx == dispatch.AssignsLen && dispatch.AssignsLen < MAXASSIGNS)
	}

	// Process each ship sequentially
	for shipIdx := range oris {
		ori := oris[shipIdx]
		des := dess[shipIdx]
		shipID := total_ship + shipIdx

		bestAssignIdx := -1
		bestCostIncrease := math.MaxFloat64
		bestOriginalCost := 0.0

		// Phase 1: try inserting into existing assigns (including currently empty ones)
		searchLimit := dispatch.AssignsLen
		if searchLimit < MAXASSIGNS {
			searchLimit++ // allow probing one fresh assign beyond current length
		}
		for assignIdx := 0; assignIdx < searchLimit; assignIdx++ {
			if !isUsable(assignIdx) {
				continue
			}
			assign := &dispatch.Assigns[assignIdx]

			// Skip assigns that are marked infeasible from earlier failures
			if assign.Cost < 0 && assign.StationsLen == 0 && assignIdx >= dispatch.AssignsLen {
				continue
			}

			// Remember original cost and stations length to roll back later
			originalCost := assign.Cost
			originalStationsLen := assign.StationsLen

			// Try adding the ship
			ok := assign.AddShip(shipID, ori, des)
			if !ok {
				// Not feasible here; ensure clean state
				if assign.StationsLen != originalStationsLen {
					assign.RemoveShip(shipID)
					assign.GenRoute()
				}
				continue
			}
			assign.GenRoute()

			newCost := assign.Cost
			costIncrease := newCost - originalCost

			// Accept only positive‑cost increases from valid routes (negative means failure)
			if newCost >= 0 && costIncrease < bestCostIncrease {
				bestCostIncrease = costIncrease
				bestAssignIdx = assignIdx
				bestOriginalCost = originalCost
			}

			// Rollback trial insertion
			assign.RemoveShip(shipID)
			assign.GenRoute()
			assign.Cost = originalCost
		}

		// Phase 2: if no feasible insertion found among existing/one‑beyond slots,
		// open a brand‑new assign (if capacity permits)
		if bestAssignIdx == -1 {
			if dispatch.AssignsLen < MAXASSIGNS {
